182→export const uploadOpinionReplyService = async(parent_id, opinion, user_id) =>{
183→    if(!parent_id || !user_id){
184→        throw new AppError(400, 'parentid or userid is undefined');
185→    }
186→    if(!opinion || typeof opinion !== 'string'){
187→        throw new AppError(400, 'opinion is undefined or opinion is not a string');
188→    }
189→
190→    const {data: parentOpinion, error: errorParentOpinion} = await supabase
191→    .from('opinions')
192→    .select('user_id')
193→    .eq('id', parent_id)
194→    .maybeSingle();
195→
196→    if(errorParentOpinion){
197→        console.error('supabase error while fetching parent opinion', errorParentOpinion.message);
198→        throw new AppError(500, 'supabase error while fetching parent opinion');
199→    }
200→    if(!parentOpinion?.user_id){
201→        throw new AppError(404, 'parent opinion not found');
202→    }
203→
204→    const receiver_id = parentOpinion.user_id;
205→    const isOwner = user_id === receiver_id;
206→
207→    const insertNotifPromise = supabase
208→    .from('notification_opinions')
209→    .insert({type: 'reply', read: false, receiver_id: receiver_id, sender_id: user_id, opinion_id: parent_id})
210→
211→    const insertOpinionReplyPromise = supabase
212→    .from('opinions')
213→    .insert({user_id: user_id, parent_id: parent_id, opinion: opinion})
214→
215→    const [ insertNotif, insertOpinionReply] = await Promise.all([
216→        isOwner ? Promise.resolve({error: null}) : insertNotifPromise, insertOpinionReplyPromise
217→    ])
218→    const {error: errorUploadOpinionReply} = insertOpinionReply;
219→    const {error: errorInsertNotif} = insertNotif;
220→
221→    if(errorUploadOpinionReply || errorInsertNotif) {
222→        console.error('supabase error:', errorInsertNotif?.message || errorUploadOpinionReply?.message);
223→        throw new AppError(500, 'supabase error');
224→    }
225→
226→    return {message: 'success'};
227→}
