        const previousComments = queryClient.getQueryData(['postComments', postId]);
        const previousJournalCaches = [
            ...queryClient.getQueriesData({ queryKey: ['journals'] }),
            ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
