                <div className="oe-body">
                    <textarea
                        maxLength={280}
                        value={opinion}
                        onChange={(e) => setOpinion(e.target.value)}
                        className="oe-textarea"
                        name="opinions"
                        placeholder="What's on your mind..."
                        rows={5}
