237→
238→    const insertNotifPromise = supabase
239→    .from('notification_opinions')
240→    .insert({type: 'reply', read: false, receiver_id: receiver_id, sender_id: user_id, opinion_id: parent_id})
241→
242→    const insertOpinionReplyPromise = supabase
243→    .from('opinions')
244→    .insert({user_id: user_id, parent_id: parent_id, opinion: opinion})
245→
246→    const [ insertNotif, insertOpinionReply] = await Promise.all([
247→        isOwner ? Promise.resolve({error: null}) : insertNotifPromise, insertOpinionReplyPromise
248→    ])
