260→export const repostService = async(sourceJournalId, caption, userId) => {
261→    if(!sourceJournalId || !userId){
262→        throw new AppError(400, 'sourceJournalId or userId is undefined');
263→    }
264→
265→    if(caption && caption.length > 280){
266→        throw new AppError(400, 'caption must be 280 characters or less');
267→    }
268→
269→    // Fetch source journal
270→    const {data: sourceJournal, error: errorSourceJournal} = await supabase
271→        .from('journals')
272→        .select('id, title, user_id, privacy, is_repost, repost_source_journal_id')
273→        .eq('id', sourceJournalId)
274→        .maybeSingle();
275→
276→    if(errorSourceJournal){
277→        console.error('supabase error while fetching source journal:', errorSourceJournal.message);
278→        throw new AppError(500, 'supabase error while fetching source journal');
279→    }
280→
281→    if(!sourceJournal){
282→        throw new AppError(404, 'source journal not found');
283→    }
284→
285→    if(sourceJournal.privacy !== 'public'){
286→        throw new AppError(403, 'cannot repost a private post');
287→    }
288→
289→    if(sourceJournal.user_id === userId){
290→        throw new AppError(403, 'cannot repost your own post');
