292→
293→    // If reposting a repost, follow chain to the ultimate original
294→    let ultimateSourceId = sourceJournalId;
295→    let ultimateSourceUserId = sourceJournal.user_id;
296→    let ultimateSourceTitle = sourceJournal.title;
